#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if(!(cin>>n)) return 0;
    vector<long long> rating(n);
    for(int i=0;i<n;++i) cin>>rating[i];
    vector<long long> candy(n,1);
    for(int i=1;i<n;++i){
        if(rating[i]>rating[i-1]) candy[i]=candy[i-1]+1;
    }
    for(int i=n-2;i>=0;--i){
        if(rating[i]>rating[i+1] && candy[i]<=candy[i+1])
            candy[i]=candy[i+1]+1;
    }
    long long total=0;
    for(long long c: candy) total+=c;
    cout<<total;
    return 0;
}
